pub const HTTP_CALL_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000801");
pub const LLM_CALL_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000802");
pub const LONG_RUNNING_HTTP_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000805");
pub const ZK_TWO_PHASE_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000806");
pub const FHE_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000807");
pub const IMAGE_CALL_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000818");
pub const AUDIO_CALL_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000819");
pub const VIDEO_CALL_PRECOMPILE: Address = address!("0x000000000000000000000000000000000000081A");
pub const SOVEREIGN_AGENT_PRECOMPILE: Address = address!("0x000000000000000000000000000000000000080C");
pub const DKMS_KEY_PRECOMPILE: Address = address!("0x000000000000000000000000000000000000081B");
pub const PERSISTENT_AGENT_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000820");

pub struct BasicAsyncCallResult { pub precompile_address: Address, pub input: Bytes, pub program_counter: Option<u64>, pub caller_address: Address }

fn call(&mut self, _context: &mut CTX, inputs: &mut CallInputs) -> Option<CallOutcome> {
    if inputs.target_address == HTTP_CALL_PRECOMPILE
        || inputs.target_address == LLM_CALL_PRECOMPILE
        || inputs.target_address == LONG_RUNNING_HTTP_PRECOMPILE
        || inputs.target_address == ZK_TWO_PHASE_PRECOMPILE
        || inputs.target_address == FHE_PRECOMPILE
        || inputs.target_address == SOVEREIGN_AGENT_PRECOMPILE
        || inputs.target_address == IMAGE_CALL_PRECOMPILE
        || inputs.target_address == AUDIO_CALL_PRECOMPILE
        || inputs.target_address == VIDEO_CALL_PRECOMPILE
        || inputs.target_address == DKMS_KEY_PRECOMPILE
        || inputs.target_address == PERSISTENT_AGENT_PRECOMPILE
    {
        self.async_call_count += 1;
        if !self.has_async_call {
            self.has_async_call = true;
            self.precompile_address = Some(inputs.target_address);
            self.precompile_input = Some(inputs.input.clone());
            self.program_counter = self.rolling_program_counter.or(Some(0));
            self.caller_address = Some(inputs.caller);
        }
    }
    None
}

fn step(
    &mut self,
    interp: &mut revm::interpreter::Interpreter<EthInterpreter>,
    _context: &mut CTX,
) {
    let pc = interp.bytecode.pc() as u64;
    self.rolling_program_counter = Some(pc);
}
